import{_ as a,o as t,c as n,ag as o}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Schedule and Tournaments","description":"","frontmatter":{},"headers":[],"relativePath":"schedule/index.md","filePath":"schedule/index.md"}'),r={name:"schedule/index.md"};function s(l,e,i,d,c,m){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="schedule-and-tournaments" tabindex="-1">Schedule and Tournaments <a class="header-anchor" href="#schedule-and-tournaments" aria-label="Permalink to &quot;Schedule and Tournaments&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Schedule screen tracks your upcoming and completed games and tournaments. Pre-scheduling games connects them to game sessions so you avoid duplicate data entry.</p><h2 id="scheduling-a-game" tabindex="-1">Scheduling a Game <a class="header-anchor" href="#scheduling-a-game" aria-label="Permalink to &quot;Scheduling a Game&quot;">​</a></h2><ol><li>Navigate to <strong>Schedule</strong></li><li>Tap <strong>+ Game</strong></li><li>Select opponent from your saved opponents list or add a new one</li><li>Enter date, time, and location</li><li>Select Home or Away</li><li>Save</li></ol><h2 id="starting-a-scheduled-game" tabindex="-1">Starting a Scheduled Game <a class="header-anchor" href="#starting-a-scheduled-game" aria-label="Permalink to &quot;Starting a Scheduled Game&quot;">​</a></h2><p>When you start a Game session the app checks for scheduled games and presents them as options. Selecting a scheduled game pre-fills all game details automatically.</p><h2 id="tournaments" tabindex="-1">Tournaments <a class="header-anchor" href="#tournaments" aria-label="Permalink to &quot;Tournaments&quot;">​</a></h2><p>Travel teams typically play 4-8 games over a tournament weekend with pool play followed by bracket play.</p><p><strong>Adding a tournament:</strong></p><ol><li>Tap <strong>+ Tournament</strong></li><li>Enter tournament name, location, dates, and format</li><li>Save</li></ol><p><strong>Adding games to a tournament:</strong> From the tournament detail screen add pool play games (opponents known in advance) and bracket games (opponents TBD until bracket is announced).</p><p><strong>TBD opponents:</strong> Schedule bracket game slots without knowing the opponent. When the bracket is announced edit the game to add the opponent name.</p><p><strong>Tournament results:</strong> Mark each game result as it is played. When the tournament is complete tap <strong>Mark Complete</strong> and record your final placement — Champion, Runner-Up, Semi-Final, Quarter-Final, or Pool Play Only.</p><p>Champion and Runner-Up placements display as badges on the tournament card and contribute to your season summary on the dashboard.</p><h2 id="recording-game-results" tabindex="-1">Recording Game Results <a class="header-anchor" href="#recording-game-results" aria-label="Permalink to &quot;Recording Game Results&quot;">​</a></h2><p>After a game tap <strong>Enter Result</strong> on the game card. Enter the final score — Win/Loss/Tie calculates automatically.</p><p>If the game was scored live through the Game Hub the result saves automatically when you end the game session.</p>',18)])])}const p=a(r,[["render",s]]);export{h as __pageData,p as default};
